sn_aia_tool.script:
(function(inputs) {
    try {

        // Validate input object
        if (!inputs) {
            return "Error: No inputs provided to the tool call.";
        }

        // Read inputs safely
        var userQuestion = inputs.question ? inputs.question.toString().trim() : "";
        var sysIdofRecord = inputs.user_id ? inputs.user_id.toString().trim() : "";

        // Mandatory validation
        if (!userQuestion) {
            return "Error: User question is missing.";
        }

        if (!sysIdofRecord) {
            return "Error: Logged-in user information is missing.";
        }

        // Initialize main service
        var genAIUtil = new IncentNowCopilotService();

        // Get final response from Script Include
        var result = genAIUtil.getResponse(
            userQuestion,
            sysIdofRecord
        );

        // Handle empty response safely
        if (!result) {
            return "No relevant data found for your request.";
        }

        return result;

    } catch (ex) {

        gs.error("[IncentNow Tool] Exception occurred: " + ex.message);

        return "Error: Unable to process your request at the moment. Please try again later.";
    }

})(inputs);
